// TestReproPreviewV3ScriptFailure reproduces a Plutus V3 script validation
// failure observed on preview network at block 4075208, slot 105803524.
//
// TX: 7e32983975bd529484ac5d4f2e930d5e8e98a5dcc2dabbc64880da60d294081d
// Script hash: 95caf9f1a99305b7360a95cbb71efd9608c2665d4f7217ab41deb420
// Error: "execute script: error explicitly called"
// isValid: true (block producer validated it successfully)
//
// This TX is a cross-chain bridge script using secp256k1 ECDSA signature
// verification. The script failed in our Plutus VM but passed on cardano-node.
func TestReproPreviewV3ScriptFailure(t *testing.T) {
	// Failing TX CBOR (captured from WARN log)
	failingTxHex := ""

	// Parent TX 3a22f18f... (provides outputs #1 and #2)
	parentTx1Hex := ""

	// Parent TX 74cc932d... (provides output #2)
	parentTx2Hex := ""

	// Step 1: Decode the failing TX
	failingTxBytes, err := hex.DecodeString(failingTxHex)
	require.NoError(t, err, "decode failing TX")
	failingTx, err := conway.NewConwayTransactionFromCbor(failingTxBytes)
	require.NoError(t, err, "parse failing TX")
	t.Logf("Failing TX hash: %s", failingTx.Hash())
	t.Logf("Failing TX isValid: %v", failingTx.IsValid())
	t.Logf("Failing TX inputs: %d", len(failingTx.Inputs()))
	t.Logf("Failing TX outputs: %d", len(failingTx.Outputs()))

	// Step 2: Decode parent TXes to get resolved inputs
	parentTx1Bytes, err := hex.DecodeString(parentTx1Hex)
	require.NoError(t, err, "decode parent TX 1")
	pTx1, err := conway.NewConwayTransactionFromCbor(parentTx1Bytes)
	require.NoError(t, err, "parse parent TX 1")
	t.Logf("Parent TX 1 hash: %s (outputs: %d)", pTx1.Hash(), len(pTx1.Outputs()))

	parentTx2Bytes, err := hex.DecodeString(parentTx2Hex)
	require.NoError(t, err, "decode parent TX 2")
	pTx2, err := conway.NewConwayTransactionFromCbor(parentTx2Bytes)
	require.NoError(t, err, "parse parent TX 2")
	t.Logf("Parent TX 2 hash: %s (outputs: %d)", pTx2.Hash(), len(pTx2.Outputs()))

	// Step 3: Build resolved inputs
	// Failing TX inputs:
	//   3a22f18f...#1 -> pTx1 output #1
	//   3a22f18f...#2 -> pTx1 output #2
	//   74cc932d...#2 -> pTx2 output #2
	pTx1Outputs := pTx1.Outputs()
	pTx2Outputs := pTx2.Outputs()

	resolvedInputs := []lcommon.Utxo{
		{
			Id:     shelley.NewShelleyTransactionInput(pTx1.Hash().String(), 1),
			Output: pTx1Outputs[1],
		},
		{
			Id:     shelley.NewShelleyTransactionInput(pTx1.Hash().String(), 2),
			Output: pTx1Outputs[2],
		},
		{
			Id:     shelley.NewShelleyTransactionInput(pTx2.Hash().String(), 2),
			Output: pTx2Outputs[2],
		},
	}

	// Log resolved input details
	for i, ri := range resolvedInputs {
		t.Logf("Resolved input %d: %s", i, ri.Id)
		t.Logf("  Address: %s", ri.Output.Address())
		t.Logf("  Amount: %s", ri.Output.Amount())
		t.Logf("  Datum: %v", ri.Output.Datum())
		t.Logf("  DatumHash: %v", ri.Output.DatumHash())
		t.Logf("  Assets: %v", ri.Output.Assets())
	}

	// Step 4: Build TxInfoV3
	slotState := mockSlotState{
		// Preview network: Shelley start = 2022-11-01 00:00:00 UTC
		ZeroTime:   time.Date(2022, 11, 1, 0, 0, 0, 0, time.UTC),
		ZeroSlot:   0,
		SlotLength: time.Second,
	}
	txInfoV3, err := script.NewTxInfoV3FromTransaction(
		slotState,
		failingTx,
		resolvedInputs,
	)
	require.NoError(t, err, "build TxInfoV3")

	// Step 5: Get the script and redeemer
	t.Logf("TxInfoV3 redeemers: %d", len(txInfoV3.Redeemers))
	t.Logf("TxInfoV3 inputs: %d", len(txInfoV3.Inputs))

	// Find the spending redeemer (tag=0, index=0)
	require.NotEmpty(t, txInfoV3.Redeemers, "no redeemers in TxInfoV3")

	// Get the script from witnesses
	v3Scripts := failingTx.Witnesses().PlutusV3Scripts()
	require.NotEmpty(t, v3Scripts, "no V3 scripts in witness")
	t.Logf("V3 script hash: %s", v3Scripts[0].Hash())

	// Step 6: Build ScriptContext and evaluate each redeemer
	for _, redeemerPair := range txInfoV3.Redeemers {
		purpose := redeemerPair.Key
		redeemer := redeemerPair.Value

		t.Logf("Evaluating redeemer: tag=%d, index=%d, scriptHash=%s",
			redeemer.Tag, redeemer.Index, purpose.ScriptHash())

		sc := script.NewScriptContextV3(txInfoV3, redeemer, purpose)
		scPd := sc.ToPlutusData()

		// Use preview PV10 cost model (placeholder - the exact values don't matter
		// for reproducing the logical error, only for budget checking)
		costModel := getPreviewV3CostModel()

		evalContext, err := cek.NewEvalContext(
			lang.LanguageVersionV3,
			cek.ProtoVersion{Major: 10, Minor: 0},
			costModel,
		)
		require.NoError(t, err, "build eval context")

		// Find the matching script
		var matchingScript lcommon.PlutusV3Script
		for _, s := range v3Scripts {
			if s.Hash() == purpose.ScriptHash() {
				matchingScript = s
				break
			}
		}
		require.NotNil(t, matchingScript, "no matching script for hash %s", purpose.ScriptHash())

		// Evaluate with generous budget (mainnet maxTxExUnits: 14M mem, 10B steps)
		budget := lcommon.ExUnits{
			Memory: 14000000,
			Steps:  10000000000,
		}
		usedBudget, err := matchingScript.Evaluate(scPd, budget, evalContext)
		if err != nil {
			t.Errorf("script evaluation failed: %s", err)
			t.Logf("Used budget: mem=%d, steps=%d", usedBudget.Memory, usedBudget.Steps)
		} else {
			t.Logf("Script PASSED. Used budget: mem=%d, steps=%d",
				usedBudget.Memory, usedBudget.Steps)
		}
	}
}

